import { Component, OnInit, OnDestroy } from '@angular/core';
import { Subscription } from 'rxjs';
import { TaskService } from '../../services/task.service';
import { TaskStats } from '../../models/task.model';

@Component({
  selector: 'app-task-stats',
  templateUrl: './task-stats.component.html',
  styleUrls: ['./task-stats.component.css'],
})
export class TaskStatsComponent implements OnInit, OnDestroy {
  stats: TaskStats = {
    total: 0,
    completed: 0,
    pending: 0,
    high_priority: 0,
    medium_priority: 0,
    low_priority: 0,
  };

  private sub!: Subscription;
  private interval: any;

  constructor(private taskService: TaskService) {}

  ngOnInit(): void {
    this.loadStats();
    this.interval = setInterval(() => this.loadStats(), 3000);
  }

  ngOnDestroy(): void {
    if (this.sub) this.sub.unsubscribe();
    if (this.interval) clearInterval(this.interval);
  }

  loadStats(): void {
    this.sub = this.taskService.getStats().subscribe({
      next: (data) => (this.stats = data),
      error: (err) => console.error('Failed to load stats', err),
    });
  }

  get completionRate(): number {
    if (this.stats.total === 0) return 0;
    return Math.round((this.stats.completed / this.stats.total) * 100);
  }
}
<div class="stats-dashboard">
  <div class="stat-card total">
    <div class="stat-icon"><i class="fas fa-layer-group"></i></div>
    <div class="stat-info">
      <span class="stat-value">{{ stats.total }}</span>
      <span class="stat-label">Total Tasks</span>
    </div>
  </div>

  <div class="stat-card completed">
    <div class="stat-icon"><i class="fas fa-check-circle"></i></div>
    <div class="stat-info">
      <span class="stat-value">{{ stats.completed }}</span>
      <span class="stat-label">Completed</span>
    </div>
  </div>

  <div class="stat-card pending">
    <div class="stat-icon"><i class="fas fa-clock"></i></div>
    <div class="stat-info">
      <span class="stat-value">{{ stats.pending }}</span>
      <span class="stat-label">Pending</span>
    </div>
  </div>

  <div class="stat-card rate">
    <div class="stat-icon"><i class="fas fa-chart-pie"></i></div>
    <div class="stat-info">
      <span class="stat-value">{{ completionRate }}%</span>
      <span class="stat-label">Done</span>
    </div>
    <div class="progress-bar">
      <div class="progress-fill" [style.width.%]="completionRate"></div>
    </div>
  </div>
</div>
